class Solution:
    def findCircleNum(self, isConnected: List[List[int]]) -> int:
        n = len(isConnected)
        seen = [False]*n
        def dfs(u):
            seen[u] = True
            for v in range(n):
                if isConnected[u][v] and not seen[v]:
                    dfs(v)
        ans = 0
        for i in range(n):
            if not seen[i]:
                dfs(i)
                ans += 1
        return ans

