class Solution {
public:
    int findCircleNum(vector<vector<int>>& isConnected) {
        int n = isConnected.size();
        vector<bool> seen(n);
        function<void(int)> dfs = [&](int u) {
            seen[u] = true;
            for (int v = 0; v < n; v++)
                if (isConnected[u][v] && !seen[v]) dfs(v);
        };
        int ans = 0;
        for (int i = 0; i < n; i++)
            if (!seen[i]) { dfs(i); ans++; }
        return ans;
    }
};
